messages.content:
看起来 `embed_multimodal` 方法没有被正确覆盖，或者 `super().embed_multimodal()` 调用了错误的父类方法。让我提供一个**完全独立实现**的版本，不依赖父类的 `embed_multimodal`。

---

## 🔧 完整修复方案

### 替换整个 `Qwen3VLMLAForConditionalGeneration` 类

```python
@MULTIMODAL_REGISTRY.register_processor(
    Qwen3VLMultiModalProcessor,
    info=Qwen3VLProcessingInfo,
    dummy_inputs=Qwen3VLDummyInputsBuilder,
)
class Qwen3VLMLAForConditionalGeneration(nn.Module, SupportsMultiModal, SupportsLoRA, SupportsPP, SupportsMRoPE):
    """
    Qwen3-VL with MLA (Multi-head Latent Attention).
    Complete reimplementation to handle DeepStack correctly.
    """

    packed_modules_mapping = {
        "qkv_proj": ["q_proj", "k_proj", "v_proj"],
        "gate_up_proj": ["gate_proj", "up_proj"],
        "qkv": ["qkv"],
    }
    supports_encoder_tp_data = True

    hf_to_vllm_mapper = WeightsMapper(
        orig_to_new_prefix={
            "model.visual.": "visual.",
            "lm_head.": "language_model.lm_head.",
            "model.language_model.": "language_model.model.",
        }
    )

    def __init__(self, *, vllm_config: VllmConfig, prefix: str = "model"):
        super().__init__()

        config = vllm_config.model_config.hf_config
        quant_config = vllm_config.quant_config
        multimodal_config = vllm_config.model_config.multimodal_config

        self.config = config
        self.multimodal_config = multimodal_config
        self.use_data_parallel = multimodal_config.mm_encoder_tp_mode == "data"
        self.video_pruning_rate = multimodal_config.video_pruning_rate
        self.is_multimodal_pruning_enabled = (
            multimodal_config.is_multimodal_pruning_enabled()
        )

        # Vision encoder
        if multimodal_config.get_limit_per_prompt("image") or \
           multimodal_config.get_limit_per_prompt("video"):
            self.visual = Qwen3_VisionTransformer(
                config.vision_config,
                norm_eps=getattr(config, "rms_norm_eps", 1e-6),
                quant_config=quant_config,
                multimodal_config=multimodal_config,
                prefix=maybe_prefix(prefix, "visual"),
            )
        else:
            self.visual = None

        # Language model with MLA
        from vllm.model_executor.models.qwen3 import Qwen3ForCausalLM
        self.language_model = Qwen3ForCausalLM(
            vllm_config=vllm_config,
            prefix=maybe_prefix(prefix, "language_model"),
        )
        # Replace model backbone
        self.language_model.model = Qwen3VLMLAModel(
            vllm_config=vllm_config,
            prefix=maybe_prefix(prefix, "language_model.model"),
        )

        # DeepStack setup
        self.use_deepstack = hasattr(config.vision_config, "deepstack_visual_indexes")
        self.deepstack_num_level = (
            len(config.vision_config.deepstack_visual_indexes)
            if self.use_deepstack
            else 0
        )

        if self.use_deepstack and self.visual is not None:
            self.visual_dim = config.vision_config.out_hidden_size
            self.multiscale_dim = self.visual_dim * self.deepstack_num_level

            self.deepstack_input_embeds = [
                torch.zeros(
                    vllm_config.scheduler_config.max_num_batched_tokens,
                    config.text_config.hidden_size,
                )
                for _ in range(self.deepstack_num_level)
            ]

        self.make_empty_intermediate_tensors = (
            self.language_model.make_empty_intermediate_tensors
        )
        self.rope_deltas = None

    @classmethod
    def get_placeholder_str(cls, modality: str, i: int) -> str | None:
        if modality.startswith("image"):
            return "<|vision_start|><|image_pad|><|vision_end|>"
        if modality.startswith("video"):
            return "<|vision_start|><|video_pad|><|vision_end|>"
        raise ValueError("Only image or video modality is supported")

    def _parse_and_validate_image_input(self, **kwargs) -> dict | None:
        """Parse image inputs from kwargs"""
        pixel_values = kwargs.pop("pixel_values", None)
        image_embeds = kwargs.pop("image_embeds", None)
        image_grid_thw = kwargs.pop("image_grid_thw", None)

        if pixel_values is None and image_embeds is None:
            return None

        if pixel_values is not None:
            return {
                "type": "pixel_values",
                "pixel_values": pixel_values,
                "image_grid_thw": image_grid_thw,
            }

        return {
            "type": "image_embeds",
            "image_embeds": image_embeds,
            "image_grid_thw": image_grid_thw,
        }

    def _parse_and_validate_video_input(self, **kwargs) -> dict | None:
        """Parse video inputs from kwargs"""
        pixel_values_videos = kwargs.pop("pixel_values_videos", None)
        video_embeds = kwargs.pop("video_embeds", None)
        video_grid_thw = kwargs.pop("video_grid_thw", None)
        second_per_grid_ts = kwargs.pop("second_per_grid_ts", None)

        if pixel_values_videos is None and video_embeds is None:
            return None

        if pixel_values_videos is not None:
            return {
                "type": "pixel_values_videos",
                "pixel_values_videos": pixel_values_videos,
                "video_grid_thw": video_grid_thw,
                "second_per_grid_ts": second_per_grid_ts,
            }

        return {
            "type": "video_embeds",
            "video_embeds": video_embeds,
            "video_grid_thw": video_grid_thw,
        }

    def _process_image_input(self, image_input: dict) -> tuple[torch.Tensor, ...]:
        """Process image inputs through vision encoder"""
        grid_thw = image_input["image_grid_thw"]

        if image_input["type"] == "image_embeds":
            image_embeds = image_input["image_embeds"].type(self.visual.dtype)
        else:
            pixel_values = image_input["pixel_values"].type(self.visual.dtype)
            if self.use_data_parallel:
                from .vision import run_dp_sharded_mrope_vision_model
                return run_dp_sharded_mrope_vision_model(
                    self.visual, pixel_values, grid_thw.tolist(), rope_type="rope_3d"
                )
            else:
                image_embeds = self.visual(pixel_values, grid_thw=grid_thw)

        # Split embeddings
        merge_size = self.visual.spatial_merge_size
        sizes = (grid_thw.prod(-1) // merge_size // merge_size).tolist()
        return image_embeds.split(sizes)

    def _process_video_input(self, video_input: dict) -> tuple[torch.Tensor, ...]:
        """Process video inputs through vision encoder"""
        grid_thw = video_input["video_grid_thw"]

        if video_input["type"] == "video_embeds":
            video_embeds = video_input["video_embeds"].type(self.visual.dtype)
        else:
            pixel_values_videos = video_input["pixel_values_videos"].type(self.visual.dtype)
            if self.use_data_parallel:
                from .vision import run_dp_sharded_mrope_vision_model
                return run_dp_sharded_mrope_vision_model(
                    self.visual, pixel_values_videos, grid_thw.tolist(), rope_type="rope_3d"
                )
            else:
                video_embeds = self.visual(pixel_values_videos, grid_thw=grid_thw)

        merge_size = self.visual.spatial_merge_size
        sizes = (grid_thw.prod(-1) // merge_size // merge_size).tolist()
        return video_embeds.split(sizes)

    def embed_multimodal(self, **kwargs: object) -> tuple[torch.Tensor, ...] | None:
        """
        ✅ 完全重写的 embed_multimodal，正确处理 DeepStack
        """
        # Parse inputs
        image_input = self._parse_and_validate_image_input(**kwargs)
        video_input = self._parse_and_validate_video_input(**kwargs)

        if image_input is None and video_input is None:
            return None

        multimodal_embeddings: list[torch.Tensor] = []

        # Process images
        if image_input is not None:
            image_embeddings = self._process_image_input(image_input)

            # ✅ 分离 DeepStack 特征
            if self.use_deepstack:
                for emb in image_embeddings:
                    # emb shape: [seq_len, total_hidden_size]
                    # total_hidden_size = visual_dim * (1 + num_deepstack_levels)
                    if emb.shape[-1] == self.visual_dim + self.multiscale_dim:
                        # 分离主特征
                        main_emb = emb[:, :self.visual_dim]

                        # 分离并保存 DeepStack 特征
                        multiscale_emb = emb[:, self.visual_dim:].view(
                            emb.shape[0], self.deepstack_num_level, self.visual_dim
                        ).permute(1, 0, 2)  # [num_levels, seq_len, hidden_size]

                        # 保存到缓冲区
                        seq_len = emb.shape[0]
                        for level_idx in range(self.deepstack_num_level):
                            self.deepstack_input_embeds[level_idx][:seq_len].copy_(
                                multiscale_emb[level_idx]
                            )

                        multimodal_embeddings.append(main_emb)
                    else:
                        # 没有 DeepStack 特征
                        multimodal_embeddings.append(emb)
            else:
                multimodal_embeddings.extend(image_embeddings)

        # Process videos
        if video_input is not None:
            video_embeddings = self._process_video_input(video_input)

            # ✅ 同样处理视频的 DeepStack
            if self.use_deepstack:
                for emb in video_embeddings:
                    if emb.shape[-1] == self.visual_dim + self.multiscale_dim:
                        main_emb = emb[:, :self.visual_dim]

                        multiscale_emb = emb[:, self.visual_dim:].view(
                            emb.shape[0], self.deepstack_num_level, self.visual_dim
                        ).permute(1, 0, 2)

                        seq_len = emb.shape[0]
                        for level_idx in range(self.deepstack_num_level):
                            self.deepstack_input_embeds[level_idx][:seq_len].copy_(
                                multiscale_emb[level_idx]
                            )

                        multimodal_embeddings.append(main_emb)
                    else:
                        multimodal_embeddings.append(emb)
            else:
                multimodal_embeddings.extend(video_embeddings)

        return tuple(multimodal_embeddings)

    # 其他必要的方法（从 Qwen3VLForConditionalGeneration 复制）
    def get_language_model(self) -> nn.Module:
        return self.language_model

    def compute_logits(self, hidden_states: torch.Tensor) -> torch.Tensor | None:
        return self.language_model.compute_logits(hidden_states)

    def load_weights(self, weights: Iterable[tuple[str, torch.Tensor]]) -> set[str]:
        from .utils import AutoWeightsLoader
        skip_prefixes = []
        if self.visual is None:
            skip_prefixes.extend(["visual."])
        loader = AutoWeightsLoader(self, skip_prefixes=skip_prefixes)
        return loader.load_weights(weights, mapper=self.hf_to_vllm_mapper)
